// src/services/userService.js

import { db } from "./firebase";

import {
  collection,
  doc,
  getDocs,
  addDoc,
  updateDoc,
  deleteDoc,
  setDoc
} from "firebase/firestore";


// =============================
// SKILLS
// =============================

// fetch all skills for logged-in user
export async function getSkills(userId) {

  const ref =
  collection(
    db,
    "users",
    userId,
    "skills"
  );

  const snapshot =
  await getDocs(ref);

  return snapshot.docs.map(doc => ({

    id: doc.id,
    ...doc.data()

  }));

}



// add new skill
export async function addSkill(userId, skill) {

  const ref =
  collection(
    db,
    "users",
    userId,
    "skills"
  );

  const docRef =
  await addDoc(ref, {

    name: skill.name,
    category: skill.category || "Other",
    level: skill.level || 50,
    createdAt: new Date()

  });

  return docRef.id;

}



// update existing skill
export async function updateSkill(userId, skillId, updates) {

  const ref =
  doc(
    db,
    "users",
    userId,
    "skills",
    skillId
  );

  await updateDoc(ref, {

    ...updates,
    updatedAt: new Date()

  });

}



// delete skill
export async function deleteSkill(userId, skillId) {

  const ref =
  doc(
    db,
    "users",
    userId,
    "skills",
    skillId
  );

  await deleteDoc(ref);

}



// =============================
// ANALYSIS
// =============================

// fetch saved analyses
export async function getAnalyses(userId) {

  const ref =
  collection(
    db,
    "users",
    userId,
    "analysis"
  );

  const snapshot =
  await getDocs(ref);

  return snapshot.docs.map(doc => ({

    id: doc.id,
    ...doc.data()

  }));

}



// save new analysis result
export async function saveAnalysis(userId, data) {

  await addDoc(

    collection(
      db,
      "users",
      userId,
      "analysis"
    ),

    {
      ...data,
      createdAt: new Date()
    }

  );

}



// =============================
// ACTIVITY TRACKING
// =============================

// log daily activity
export async function logActivity(userId, date) {

  await setDoc(

    doc(
      db,
      "users",
      userId,
      "activity",
      date
    ),

    {
      date,
      updatedAt: new Date()
    }

  );

}



// fetch activity history
export async function getActivity(userId) {

  const ref =
  collection(
    db,
    "users",
    userId,
    "activity"
  );

  const snapshot =
  await getDocs(ref);

  return snapshot.docs.map(doc => doc.data());

}
